import{_ as o,o as t,c as s,a2 as a}from"./chunks/framework.ChW7XBuO.js";const u=JSON.parse('{"title":"目录结构","description":"rolebox 项目的目录结构说明 — 角色目录、技能、函数、引用、子代理的组织方式","frontmatter":{"title":"目录结构","description":"rolebox 项目的目录结构说明 — 角色目录、技能、函数、引用、子代理的组织方式"},"headers":[],"relativePath":"01-Overview/directory-structure.md","filePath":"01-Overview/directory-structure.md"}'),d={name:"01-Overview/directory-structure.md"};function n(c,e,r,l,i,p){return t(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h1><blockquote><p><strong>相关文档：</strong> <a href="/rolebox-docs/01-Overview/quick-start.html">快速开始</a> — 5 分钟上手 rolebox | <a href="/rolebox-docs/02-Guide/create-a-role.html">创建角色</a> — 完整的角色创建指南 | <a href="/rolebox-docs/03-Reference/role-yaml.html">角色定义参考</a> — <code>role.yaml</code> 完整字段说明</p></blockquote><p>rolebox 的所有角色、技能、函数和引用文件都组织在 <code>~/.config/opencode/</code> 目录下。以下为完整的目录树，每个部分都有详细说明。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/opencode/</span></span>
<span class="line"><span>├── opencode.jsonc                  # opencode 主配置文件，声明插件</span></span>
<span class="line"><span>├── rolebox/                        # rolebox 角色根目录</span></span>
<span class="line"><span>│   ├── copywriter/                 # 角色示例：文案作者</span></span>
<span class="line"><span>│   │   └── role.yaml               # 角色配置文件（模型、技能、函数声明）</span></span>
<span class="line"><span>│   ├── code-reviewer/              # 角色示例：代码审查员</span></span>
<span class="line"><span>│   │   ├── role.yaml               # 角色定义（模型选择、提示词、行为约束）</span></span>
<span class="line"><span>│   │   ├── skills/                 # 角色私有技能目录</span></span>
<span class="line"><span>│   │   │   └── review-checklist.md # 技能文件：审查清单知识</span></span>
<span class="line"><span>│   │   ├── functions/              # 角色私有函数目录</span></span>
<span class="line"><span>│   │   │   └── plan.md             # 函数定义：可覆盖内置函数</span></span>
<span class="line"><span>│   │   └── references/             # 角色私有引用文档目录</span></span>
<span class="line"><span>│   │       └── style-guide.md      # 深度知识文档：编码规范参考</span></span>
<span class="line"><span>│   ├── team-lead/                  # 角色示例：团队领导</span></span>
<span class="line"><span>│   │   ├── role.yaml               # 父角色配置（可内联子代理定义）</span></span>
<span class="line"><span>│   │   ├── references/             # 父角色引用文档</span></span>
<span class="line"><span>│   │   │   └── architecture.md     # 架构决策参考</span></span>
<span class="line"><span>│   │   └── subagents/              # 基于文件的子代理定义</span></span>
<span class="line"><span>│   │       └── researcher/         # 子代理：研究员</span></span>
<span class="line"><span>│   │           ├── role.yaml       # 子代理角色定义</span></span>
<span class="line"><span>│   │           └── skills/         # 子代理技能目录</span></span>
<span class="line"><span>│   │               └── research-checklist/</span></span>
<span class="line"><span>│   │                   ├── SKILL.md           # 技能入口文件</span></span>
<span class="line"><span>│   │                   └── references/        # 技能级引用文档</span></span>
<span class="line"><span>│   │                       └── methodology.md # 研究方法论</span></span>
<span class="line"><span>│   └── ...                         # 更多角色目录</span></span>
<span class="line"><span>├── functions/                      # 全局用户自定义函数</span></span>
<span class="line"><span>│   └── my-custom-fn.md             # 对所有角色可见的自定义函数</span></span>
<span class="line"><span>└── skills/                         # 全局 opencode 技能</span></span>
<span class="line"><span>    └── ...                         # 可被所有角色加载的共享技能</span></span></code></pre></div><h2 id="目录与文件说明" tabindex="-1">目录与文件说明 <a class="header-anchor" href="#目录与文件说明" aria-label="Permalink to &quot;目录与文件说明&quot;">​</a></h2><h3 id="role-yaml-—-角色定义" tabindex="-1"><code>role.yaml</code> — 角色定义 <a class="header-anchor" href="#role-yaml-—-角色定义" aria-label="Permalink to &quot;\`role.yaml\` — 角色定义&quot;">​</a></h3><p>每个角色目录必须包含 <code>role.yaml</code> 文件，它是角色的声明式配置入口。内容包括：</p><ul><li><strong>模型配置</strong>：指定角色使用的 AI 模型（可从模型池中选择）</li><li><strong>系统提示词</strong>：定义角色的行为、职责和约束</li><li><strong>技能声明</strong>：列出角色可加载的技能模块</li><li><strong>函数声明</strong>：声明角色激活的内置或自定义函数</li><li><strong>子代理定义</strong>：可内联定义子代理，或通过 <code>subagents/</code> 目录引用</li><li><strong>权限与能力</strong>：配置角色的工具访问权限（文件读写、网络访问等）</li><li><strong>调度配置</strong>：并发限制、预算控制、超时设置</li></ul><p>详见 <a href="/rolebox-docs/03-Reference/role-yaml.html">角色定义 (role.yaml)</a>。</p><h3 id="skills-—-技能目录" tabindex="-1"><code>skills/</code> — 技能目录 <a class="header-anchor" href="#skills-—-技能目录" aria-label="Permalink to &quot;\`skills/\` — 技能目录&quot;">​</a></h3><p>技能是按需加载的知识模块，角色只在执行相关任务时才加载对应技能。每个技能是一个 Markdown 文件（简单技能）或一个包含 <code>SKILL.md</code> 入口文件的子目录（复杂技能，可附带 <code>references/</code> 引用文档）。</p><p>技能的分层加载优先级：</p><ol><li><strong>角色私有技能</strong>：位于 <code>{roleDir}/skills/</code> — 仅该角色可用</li><li><strong>全局技能</strong>：位于 <code>~/.config/opencode/skills/</code> — 所有角色共享</li></ol><p>技能文件命名约定：简单技能使用 <code>{name}.md</code>，复杂技能使用 <code>{name}/SKILL.md</code> 目录布局。分辨率为先目录后文件：同名的 <code>{name}/SKILL.md</code> 优先于 <code>{name}.md</code>。详见 <a href="/rolebox-docs/02-Guide/skills.html">技能系统</a>。</p><h3 id="functions-—-函数目录" tabindex="-1"><code>functions/</code> — 函数目录 <a class="header-anchor" href="#functions-—-函数目录" aria-label="Permalink to &quot;\`functions/\` — 函数目录&quot;">​</a></h3><p>函数是角色可激活的组合行为模块，通过 <code>|name|</code> 语法触发。可以是内置函数（如 <code>plan</code>、<code>execute</code>、<code>loop</code>）或自定义函数。</p><p>函数的分层覆盖优先级：</p><ol><li><strong>角色私有函数</strong>：位于 <code>{roleDir}/functions/</code> — 可覆盖内置函数</li><li><strong>全局用户函数</strong>：位于 <code>~/.config/opencode/functions/</code> — 对所有角色可见</li><li><strong>内置函数</strong>：rolebox 自带的基础函数（<code>plan</code>、<code>execute</code>、<code>loop</code>）</li></ol><p>函数通过 <code>|functionName|</code> 语法在对话中触发，支持参数化调用（如 <code>|review:security,strict|</code>）。内置函数为默认加载项，仅在 <code>role.yaml</code> 显式声明 <code>functions</code> 字段时被覆盖。详见 <a href="/rolebox-docs/02-Guide/functions.html">函数系统</a>。</p><h3 id="references-—-引用文档目录" tabindex="-1"><code>references/</code> — 引用文档目录 <a class="header-anchor" href="#references-—-引用文档目录" aria-label="Permalink to &quot;\`references/\` — 引用文档目录&quot;">​</a></h3><p>引用文档是角色或技能被动阅读的深度知识文档，在相关任务执行时自动注入到上下文中。与技能不同，引用文档不会改变角色的行为模式，而是提供领域知识上下文。</p><p>引用文档可以放在三个层级：</p><ul><li><strong>角色级</strong>：<code>{roleDir}/references/</code></li><li><strong>技能级</strong>：<code>{skillDir}/references/</code></li><li><strong>全局级</strong>：<code>~/.config/opencode/references/</code></li></ul><p>引用文档系统支持从 Markdown 头部的 <code>description</code> 字段自动提取摘要，在相关任务执行时作为上下文注入。详见 <a href="/rolebox-docs/02-Guide/references.html">引用文档</a>。</p><h3 id="subagents-—-子代理目录" tabindex="-1"><code>subagents/</code> — 子代理目录 <a class="header-anchor" href="#subagents-—-子代理目录" aria-label="Permalink to &quot;\`subagents/\` — 子代理目录&quot;">​</a></h3><p>子代理是父角色派生的专门化代理，拥有独立的角色定义、技能和提示词。父角色通过 <code>dispatch()</code> 工具将任务委托给子代理。子代理目录组织方式与普通角色完全相同（包含 <code>role.yaml</code>、<code>skills/</code>、<code>functions/</code>、<code>references/</code>）。</p><p>子代理的关键特性：</p><ul><li><strong>独立上下文</strong>：每个子代理有独立的会话上下文</li><li><strong>并发执行</strong>：多个子代理可并行运行</li><li><strong>层级嵌套</strong>：支持最多 3 级嵌套（父 → 子 → 孙）</li><li><strong>结果回传</strong>：子代理完成后将结构化结果返回给父角色</li></ul><p>详见 <a href="/rolebox-docs/02-Guide/subagents.html">子代理</a>。</p><hr><h3 id="解析优先级图" tabindex="-1">解析优先级图 <a class="header-anchor" href="#解析优先级图" aria-label="Permalink to &quot;解析优先级图&quot;">​</a></h3><p>rolebox 在运行时会按以下优先级解析技能、函数和引用文档。低优先级仅在高优先级未找到时生效：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>技能解析优先级 (src/resolver/skill-resolver.ts:22-34)</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━</span></span>
<span class="line"><span>高  1. {roleDir}/skills/{name}/SKILL.md    ← 角色私有目录技能（复杂）</span></span>
<span class="line"><span>   2. {roleDir}/skills/{name}.md            ← 角色私有单文件技能</span></span>
<span class="line"><span>   3. ~/.config/opencode/skills/{name}/SKILL.md  ← 全局目录技能</span></span>
<span class="line"><span>低  4. ~/.config/opencode/skills/{name}.md       ← 全局单文件技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>函数解析优先级 (src/function/file-resolver.ts:19-23)</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━</span></span>
<span class="line"><span>高  1. {roleDir}/functions/{name}.md        ← 角色私有（可覆盖内置）</span></span>
<span class="line"><span>   2. ~/.config/opencode/functions/{name}.md ← 全局用户函数</span></span>
<span class="line"><span>低  3. {builtinDir}/{name}.md               ← rolebox 内置函数</span></span>
<span class="line"><span></span></span>
<span class="line"><span>引用文档优先级 (src/resolver/reference-resolver.ts)</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━</span></span>
<span class="line"><span>高  1. {roleDir}/references/                ← 角色级引用</span></span>
<span class="line"><span>   2. {skillDir}/references/                ← 技能级引用</span></span>
<span class="line"><span>低  3. ~/.config/opencode/references/       ← 全局引用</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">优先级记忆口诀</p><p>三个维度的共同规律：<strong>角色本地 &gt; 全局 &gt; 内置</strong>。注意函数与引用的行为差异——函数采用<strong>覆盖</strong>策略（高优先级同名文件会屏蔽低优先级），引用采用<strong>合并</strong>策略（所有匹配的引用全部注入上下文，不存在屏蔽关系）。</p></div><h3 id="rolebox-—-运行时状态与持久化目录" tabindex="-1"><code>.rolebox/</code> — 运行时状态与持久化目录 <a class="header-anchor" href="#rolebox-—-运行时状态与持久化目录" aria-label="Permalink to &quot;\`.rolebox/\` — 运行时状态与持久化目录&quot;">​</a></h3><p>rolebox 在项目根目录下维护一个隐藏的 <code>.rolebox/</code> 目录，用于存储运行时状态、持久化数据和日志。该目录由 rolebox 自动管理，<strong>不建议手动编辑</strong>。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>.rolebox/</code> 目录已包含在 <code>.gitignore</code> 中，不会提交到版本控制。如果需要重置 rolebox 的运行时状态，可以安全地删除整个 <code>.rolebox/state/</code> 目录——rolebox 会在下次运行时自动重建。但 <code>.rolebox/memory.db</code> 包含跨会话的记忆数据，删除前请确认是否需要备份。</p></div><p>项目级配置 <code>.rolebox/config.json</code> 使用简单 JSON 格式（<code>{ &quot;defaultRole&quot;: &quot;role-name&quot; }</code>），由 <code>src/project-config.ts:42-70</code> 读取。该配置在角色解析之后、会话启动之前应用，因此不会影响 <code>rolebox list</code> 的输出，但会影响打开新会话时的默认角色选择。</p><h3 id="runtime-state-运行时状态" tabindex="-1">Runtime State (运行时状态) <a class="header-anchor" href="#runtime-state-运行时状态" aria-label="Permalink to &quot;Runtime State (运行时状态)&quot;">​</a></h3><p>运行时状态是 rolebox 执行引擎的核心数据层，对应的模块实现参见 <a href="/rolebox-docs/01-Overview/architecture-overview.html#_30-模块地图">架构概览 - 模块地图</a>。每个状态文件由对应的服务模块在运行时自动维护：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.project-root/</span></span>
<span class="line"><span>└── .rolebox/</span></span>
<span class="line"><span>    ├── memory.db                    # SQLite 持久化记忆数据库</span></span>
<span class="line"><span>    │                                # 存储跨会话、跨角色的记忆条目</span></span>
<span class="line"><span>    ├── config.json                  # 项目级配置（如默认角色）</span></span>
<span class="line"><span>    └── state/                       # 运行时状态目录</span></span>
<span class="line"><span>        ├── dispatch-{hash}.json     # 调度任务状态（含出站通知、结果引用）</span></span>
<span class="line"><span>        ├── fnstate-{hash}.json      # 函数运行时状态（阶段、门控、证据）</span></span>
<span class="line"><span>        ├── graph-{hash}.json        # 协作图执行状态（前沿、迭代计数）</span></span>
<span class="line"><span>        ├── metrics-{hash}.json      # 指标持久化（原子写入）</span></span>
<span class="line"><span>        ├── metrics-events-{hash}.ndjson  # 指标事件环形缓冲区（上限 100KB）</span></span>
<span class="line"><span>        ├── progress/{taskId}.json   # 进度报告数据</span></span>
<span class="line"><span>        ├── checkpoints/{taskId}.json # 检查点持久化（用于失败重试）</span></span>
<span class="line"><span>        └── results/{taskId}.txt     # 任务结果侧车文件（溢出文本）</span></span></code></pre></div><p>关键文件说明：</p><table tabindex="0"><thead><tr><th>文件</th><th>来源模块</th><th>用途</th></tr></thead><tbody><tr><td><code>memory.db</code></td><td><code>src/memory/store.ts</code></td><td>SQLite 数据库，存储 <code>memory_write</code> 写入的记忆条目</td></tr><tr><td><code>config.json</code></td><td><code>src/project-config.ts</code></td><td>项目级配置，设置 <code>defaultRole</code> 指定默认角色。在 <code>~/.config/opencode/</code> 全局配置之后加载，仅对该项目生效</td></tr><tr><td><code>dispatch-{hash}.json</code></td><td><code>src/dispatch/persistence/task-store.ts</code></td><td>所有调度任务的持久化状态，含任务图、结果引用、出站通知队列</td></tr><tr><td><code>fnstate-{hash}.json</code></td><td><code>src/function/runtime-store.ts</code></td><td>函数状态机的阶段/门控/证据观测记录</td></tr><tr><td><code>graph-{hash}.json</code></td><td><code>src/graph/graph-store.ts</code></td><td>协作图的前沿节点、迭代次数、终止状态</td></tr><tr><td><code>metrics-{hash}.json</code></td><td><code>src/dispatch/persistence/metrics-persister.ts</code></td><td>指标快照（计数器、仪表盘、直方图、恢复数据），由 <code>ROLEBOX_METRICS</code> 环境变量控制</td></tr><tr><td><code>metrics-events-{hash}.ndjson</code></td><td><code>src/dispatch/persistence/metrics-persister.ts</code></td><td>指标事件环形缓冲区，上限 100KB，超限后自动截断保留后半</td></tr><tr><td><code>progress/{taskId}.json</code></td><td><code>src/dispatch/progress/progress-store.ts</code></td><td>运行中任务的进度报告（阶段、百分比、消息），5 秒去抖写入</td></tr><tr><td><code>checkpoints/{taskId}.json</code></td><td><code>src/dispatch/checkpoint/checkpoint-store.ts</code></td><td>检查点数据数组，用于失败后带上下文恢复。每任务最多保留 100 条（FIFO 淘汰）</td></tr><tr><td><code>results/{taskId}.txt</code></td><td><code>src/dispatch/persistence/task-store.ts</code></td><td>任务结果侧车文件，存储超出内联限制（4KB）的 <code>dispatch_output</code> 文本</td></tr><tr><td><code>dispatch-{hash}.json.lock</code></td><td><code>src/dispatch/concurrency/state-lock.ts</code></td><td>文件锁，防止多进程并发写入冲突。5 分钟无活动自动失效回收。锁竞争时退化为只读模式</td></tr></tbody></table><p><code>{hash}</code> 是项目目录规范化后的 SHA-256 前 12 位，确保同一物理路径总是映射到相同的状态文件名。</p><h4 id="状态文件示例内容" tabindex="-1">状态文件示例内容 <a class="header-anchor" href="#状态文件示例内容" aria-label="Permalink to &quot;状态文件示例内容&quot;">​</a></h4><p>每个 JSON 状态文件的内部结构如下：</p><table tabindex="0"><thead><tr><th>文件</th><th>示例内容（缩略）</th></tr></thead><tbody><tr><td><code>dispatch-{hash}.json</code></td><td><code>{ &quot;tasks&quot;: [{ &quot;id&quot;: &quot;bg_xxx&quot;, &quot;agent&quot;: &quot;backend&quot;, &quot;status&quot;: &quot;running&quot; }] }</code></td></tr><tr><td><code>fnstate-{hash}.json</code></td><td><code>{ &quot;sessions&quot;: { &quot;sid&quot;: { &quot;phase&quot;: &quot;active&quot;, &quot;gateSatisfied&quot;: true } } }</code></td></tr><tr><td><code>graph-{hash}.json</code></td><td><code>{ &quot;version&quot;: 2, &quot;sessions&quot;: [{ &quot;sessionId&quot;: &quot;...&quot;, &quot;state&quot;: { &quot;frontier&quot;: [&quot;agent-a&quot;], &quot;iterationCount&quot;: 3 } }] }</code></td></tr><tr><td><code>metrics-{hash}.json</code></td><td><code>{ &quot;dispatchCount&quot;: 42, &quot;avgDurationMs&quot;: 1250, &quot;lastUpdated&quot;: &quot;...&quot; }</code></td></tr><tr><td><code>progress/{taskId}.json</code></td><td><code>{ &quot;stage&quot;: &quot;implementing&quot;, &quot;percentage&quot;: 60, &quot;message&quot;: &quot;处理中...&quot; }</code></td></tr><tr><td><code>checkpoints/{taskId}.json</code></td><td><code>{ &quot;phase&quot;: &quot;research&quot;, &quot;completedItems&quot;: [...], &quot;remainingItems&quot;: [...] }</code></td></tr><tr><td><code>results/{taskId}.txt</code></td><td>纯文本形式存储，内容为工具调用的完整输出</td></tr></tbody></table><p><code>{hash}</code> 经 <code>src/utils/state-paths.ts:15-17</code> 中的 <code>shortHash()</code> 函数计算（SHA-256 前 12 位十六进制），确保同一物理路径总是映射到固定的文件名。</p><h4 id="原子写入与临时文件" tabindex="-1">原子写入与临时文件 <a class="header-anchor" href="#原子写入与临时文件" aria-label="Permalink to &quot;原子写入与临时文件&quot;">​</a></h4><p>所有状态文件（<code>dispatch-*</code>、<code>graph-*</code>、<code>metrics-*</code>、<code>checkpoints/*</code>、<code>progress/*</code>）均采用 <strong>原子写入模式</strong>：先写入 <code>.tmp</code> 临时文件，再通过 <code>renameSync()</code> 覆盖目标文件。这意味着：</p><ul><li>写入中途崩溃不会产生损坏的 state 文件</li><li>读取方永远只看到完整的先前版本或完整的新版本</li><li><code>.tmp</code> 文件可以安全删除，rolebox 不会残留打开句柄</li></ul><h4 id="状态文件垃圾回收-gc" tabindex="-1">状态文件垃圾回收（GC） <a class="header-anchor" href="#状态文件垃圾回收-gc" aria-label="Permalink to &quot;状态文件垃圾回收（GC）&quot;">​</a></h4><p>rolebox 在启动时自动执行 <code>cleanExpiredState()</code>（<code>src/dispatch/persistence/state-gc.ts:23</code>），清理超过 7 天未修改的 <code>dispatch-*.json</code> 和 <code>dispatch-*.json.lock</code> 文件。可通过环境变量 <code>ROLEBOX_STATE_RETENTION_DAYS</code> 自定义保留天数。GC 为&quot;发起即忘&quot;设计，异常仅记录日志，不会阻止启动。</p><p>状态文件可通过 <code>rolebox monitor</code> 命令查看实时内容，使用 <code>--task-id=&lt;id&gt;</code> 查看特定任务的详细结果。</p><h2 id="rolebox-全局路径" tabindex="-1">rolebox 全局路径 <a class="header-anchor" href="#rolebox-全局路径" aria-label="Permalink to &quot;rolebox 全局路径&quot;">​</a></h2><p>以下全局目录位于 <code>~/.config/opencode/</code> 下，对本地开发环境中的 <strong>所有项目</strong> 可见：</p><table tabindex="0"><thead><tr><th>路径</th><th>用途</th></tr></thead><tbody><tr><td><code>~/.config/opencode/rolebox/</code></td><td>rolebox 角色同步目标，<code>rolebox sync opencode</code> 在此创建符号链接</td></tr><tr><td><code>~/.config/opencode/skills/</code></td><td>全局技能目录，所有角色可加载的共享技能</td></tr><tr><td><code>~/.config/opencode/functions/</code></td><td>全局函数目录，对所有角色可见的自定义函数</td></tr><tr><td><code>~/.config/opencode/references/</code></td><td>全局引用文档目录，跨角色共享的深度知识文档</td></tr></tbody></table><h2 id="rolebox-自身配置与数据目录" tabindex="-1">rolebox 自身配置与数据目录 <a class="header-anchor" href="#rolebox-自身配置与数据目录" aria-label="Permalink to &quot;rolebox 自身配置与数据目录&quot;">​</a></h2><p>除了上述 <code>~/.config/opencode/</code> 下的全局目录外，rolebox 在以下两个位置维护独立配置和数据：</p><h3 id="config-rolebox-—-角色管理器配置" tabindex="-1"><code>~/.config/rolebox/</code> — 角色管理器配置 <a class="header-anchor" href="#config-rolebox-—-角色管理器配置" aria-label="Permalink to &quot;\`~/.config/rolebox/\` — 角色管理器配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>用途</th><th>安全删除？</th></tr></thead><tbody><tr><td><code>config.yaml</code></td><td>注册表配置。默认包含 <code>oh-my-role</code> 注册表，记录 GitHub 仓库 URL 和默认注册表标记</td><td>删除后下次使用自动重建默认配置</td></tr><tr><td><code>rolebox.lock</code></td><td>锁文件，记录已安装角色的版本号、注册表源和完整性哈希（<code>sha256-...</code>）</td><td>删除后角色仍存在，但 <code>rolebox sync</code> 将无法找到它们</td></tr><tr><td><code>logs/rolebox.log</code></td><td>rolebox CLI 操作日志</td><td>可安全删除，自动轮转</td></tr></tbody></table><p><code>~/.config/rolebox/config.yaml</code> 与项目本地的 <code>.rolebox/config.json</code> 分工明确：config.yaml 管理<strong>角色安装和注册表</strong>（影响 <code>rolebox install</code>、<code>rolebox sync</code>），而 <code>.rolebox/config.json</code> 管理<strong>项目级运行时配置</strong>（如默认角色）。</p><h3 id="local-share-rolebox-—-角色包与缓存数据" tabindex="-1"><code>~/.local/share/rolebox/</code> — 角色包与缓存数据 <a class="header-anchor" href="#local-share-rolebox-—-角色包与缓存数据" aria-label="Permalink to &quot;\`~/.local/share/rolebox/\` — 角色包与缓存数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>路径</th><th>用途</th></tr></thead><tbody><tr><td><code>roles/{registry}/{roleId}@{version}/</code></td><td>已安装角色包的完整目录。<code>rolebox install</code> 将角色下载到此处，<code>rolebox sync</code> 从此创建符号链接到 <code>~/.config/opencode/rolebox/</code></td></tr><tr><td><code>cache/{registry}/</code></td><td>注册表清单缓存（<code>registry.yaml</code> + <code>.timestamp</code>）。默认缓存 30 分钟，可通过 <code>--no-cache</code> 跳过</td></tr></tbody></table><p>角色存储路径格式为 <code>{dataDir}/roles/{registry}/{roleId}@{version}/</code>（见 <code>src/cli/paths.ts:54-56</code>），确保同一角色不同版本可以共存。升级角色时旧版本目录被自动删除。</p><h2 id="状态迁移记录" tabindex="-1">状态迁移记录 <a class="header-anchor" href="#状态迁移记录" aria-label="Permalink to &quot;状态迁移记录&quot;">​</a></h2><h3 id="v0-12-0-—-状态存储位置迁移" tabindex="-1">v0.12.0 — 状态存储位置迁移 <a class="header-anchor" href="#v0-12-0-—-状态存储位置迁移" aria-label="Permalink to &quot;v0.12.0 — 状态存储位置迁移&quot;">​</a></h3><p>在 v0.12.0 之前（参见 <code>CHANGELOG.md:302</code>），dispatch 和 graph 状态存储在 <code>~/.local/share/rolebox/</code>（<code>XDG_DATA_HOME</code>）下。v0.12.0 将状态存储迁移到项目本地的 <code>.rolebox/</code> 目录中。这意味着：</p><ul><li><strong>旧位置</strong>（v0.12.0 前）：<code>~/.local/share/rolebox/state/dispatch-*.json</code></li><li><strong>新位置</strong>（v0.12.0 起）：<code>.rolebox/state/dispatch-*.json</code></li></ul><p>迁移由 rolebox 自动处理——启动时检测旧位置并搬移到新位置。如果发现 <code>.rolebox/state/</code> 为空而旧位置有残留，删除旧位置文件是安全的。</p><h2 id="遇到问题时该看哪个目录" tabindex="-1">遇到问题时该看哪个目录 <a class="header-anchor" href="#遇到问题时该看哪个目录" aria-label="Permalink to &quot;遇到问题时该看哪个目录&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>对应目录 / 文件</th><th>查看方法</th></tr></thead><tbody><tr><td>角色没有按预期响应，技能/函数未加载</td><td><code>~/.config/opencode/rolebox/{roleName}/</code></td><td>检查 <code>role.yaml</code> 中的 <code>skills</code> 和 <code>functions</code> 声明</td></tr><tr><td>任务卡住或状态异常</td><td><code>.rolebox/state/dispatch-{hash}.json</code></td><td><code>rolebox monitor --task-id=&lt;id&gt;</code></td></tr><tr><td>函数状态机行为异常</td><td><code>.rolebox/state/fnstate-{hash}.json</code></td><td><code>rolebox monitor</code>（过滤 Functions 面板）</td></tr><tr><td>协作图执行停滞</td><td><code>.rolebox/state/graph-{hash}.json</code></td><td><code>rolebox monitor</code>（过滤 Graph 面板）</td></tr><tr><td>进度报告丢失或不更新</td><td><code>.rolebox/state/progress/{taskId}.json</code></td><td>直接读取 JSON，检查 <code>timestamp</code> 是否更新</td></tr><tr><td>角色安装后未生效</td><td><code>~/.config/opencode/rolebox/{roleName}/</code></td><td>运行 <code>rolebox sync opencode</code>，确认符号链接存在</td></tr><tr><td>角色版本不匹配</td><td><code>~/.config/rolebox/rolebox.lock</code></td><td><code>rolebox list</code> 查看已安装版本</td></tr><tr><td>注册表下载失败</td><td><code>~/.local/share/rolebox/cache/{registry}/</code></td><td>运行 <code>rolebox search &lt;role&gt; --no-cache</code> 跳过缓存</td></tr><tr><td>跨会话记忆丢失</td><td><code>.rolebox/memory.db</code></td><td>检查文件是否存在且非空（SQLite 格式）</td></tr><tr><td>状态文件损坏需重置</td><td><code>.rolebox/state/</code></td><td>安全删除整个 <code>.rolebox/state/</code> 目录，rolebox 下次启动自动重建</td></tr><tr><td>希望完全清理所有运行时数据</td><td><code>.rolebox/</code></td><td>删除 <code>.rolebox/</code>（注意 <code>memory.db</code> 包含记忆数据，确认备份后操作）</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/rolebox-docs/01-Overview/quick-start.html">快速开始</a> — 5 分钟上手 rolebox</li><li><a href="/rolebox-docs/02-Guide/create-a-role.html">创建角色</a> — 完整的角色创建指南</li><li><a href="/rolebox-docs/03-Reference/role-yaml.html">角色定义参考</a> — <code>role.yaml</code> 完整字段说明</li></ul>`,74)])])}const b=o(d,[["render",n]]);export{u as __pageData,b as default};
